import subprocess
result = subprocess.run(['python3', 'scripts/apply_harness.py', '--list-profiles'], text=True, stdout=subprocess.PIPE, stderr=subprocess.PIPE, check=False)
assert result.returncode == 0, result.stderr or result.stdout
for profile in ['generic', 'python', 'typescript', 'nextjs', 'django', 'flask', 'fastapi', 'spring', 'android', 'react', 'vue', 'go', 'rust']:
    assert profile in result.stdout.split(), f'missing profile {profile}'
status = subprocess.check_output(['git', 'status', '--porcelain=v1'], text=True)
changed = {line[3:] for line in status.splitlines() if len(line) >= 4}
required_changed = {'scripts/apply_harness.py', 'tests/test_apply_harness.py'}
missing_changes = sorted(required_changed - changed)
assert not missing_changes, 'required files were not changed: ' + ', '.join(missing_changes)
